script.text:
      /* <flatten type="Javascript"> */
function active$EmployeeInsuranceAndUnionDueInformationFilter(f) {f.add_onResponseComplete(on$EmployeeInsuranceAndUnionDueInformationFilter$ResponseComplete);}
function close$EmployeeInsuranceAndUnionDueInformationFilter(f) {try {f.remove_onResponseComplete(on$EmployeeInsuranceAndUnionDueInformationFilter$ResponseComplete);} catch (ex) {}}
function on$EmployeeInsuranceAndUnionDueInformationFilter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._refreshMemvars = true;
      g._dateFrom = f.getItemValue('ngay_tu');
      g._dateTo = f.getItemValue('ngay_den');
      g._staff = f.getItemValue('ma_nv');
      g._dept = f.getItemValue('ma_bp');
      g._pos = f.getItemValue('vi_tri');
      g._level = f.getItemValue('ma_bac');
      break;
    default:
      break;
  }
}
/* </flatten> */
